#include <bits/stdc++.h>
using namespace std;

const int N=55;

int p,k,r,a[N],b[N],t[N];
long long n;

int main(){
    scanf("%lld%d%d%d",&n,&p,&k,&r);
    n*=k;
    a[0]=1;
    if(k>1) b[0]=b[1]=1;
    else b[0]=2%p;
    while(n){
        if(n&1){
            for(int i=0;i<k;i++){
                t[i]=0;
                for(int j=0;j<k;j++)
                    t[i]=(t[i]+1ll*a[j]*b[(k+i-j)%k])%p;
            }
            for(int i=0;i<k;i++)
                a[i]=t[i];
        }
        for(int i=0;i<k;i++){
            t[i]=0;
            for(int j=0;j<k;j++)
                t[i]=(t[i]+1ll*b[j]*b[(k+i-j)%k])%p;
        }
        for(int i=0;i<k;i++)
            b[i]=t[i];
        n>>=1;
    }
    printf("%d",a[r]);
    return 0;
}
